import scala.xml._
import akka.http.scaladsl.marshallers.xml._
import akka.http.scaladsl.server.Directives._
import akka.actor.ActorSystem
import spray.json._

implicit val system: ActorSystem = ActorSystem()
implicit val executionContext: ExecutionContext = system.dispatcher

val rootParser: Elem => Xml = (_: Elem) match {
  case xml @ "<settings>" =>
    (xml \ "setting").map( setting => (setting \ "@name").text -> setting \ "@value").toMap
  case _ => Map.empty[String, String]
}

val settingParser: Elem => Xml = (_: Elem) match {
  case xml @ "<setting name={name}>{value}</setting>" => (xml \ "@name").text -> (xml \ "@value").text
  case _ => ("", "")
}

def parseSetting(xml: Xml): Map[String, String] = {
  (xml \ "entity" | xml).flatMap(_.child) match {
    case Nil => Map.empty
    case x :: xs =>
      val entityMap = x.asInstanceOf[Elem].attributes("xmlns").getOrElse("", "").toString == "my-namespace" match {
        case true => rootParser(x)
        case false => settingParser(x)
      }

      val restEntityMap = parseSetting(xs.reduce(_ ++ _))

      entityMap ++ restEntityMap
  }
}

def settingsFromApiRequest(xmlString: String): Future[Map[String, String]] = Future {
  parseSetting(XML.loadString(xmlString))
}.map(_.toSeq.sortBy(_._1)).map(_.toMap)

val route = path("settings") {
  get {
    completeWithFS {
      entitiesRequest =>
        entitiesRequest.asJson.flatMap { json =>
          json.convertTo[String].flatMap(settingsFromApiRequest).map { settings =>
            Complete(settings, StatusCodes.OK)
          }
        }
    }
  }
}

val server = Http().bindAndHandle(route, interface = "localhost", port = 8080)